class NQueensSolver:
    def __init__(self, size):
        self.size = size
        self.board = [-1] * size  # using a list to store positions of queens where index is row and value is column

    def solve(self):
        self._backtrack(0)
        return self._create_output()

    def _backtrack(self, row):
        if row == self.size:
            return True
        for col in range(self.size):
            if self._is_valid(row, col):
                self.board[row] = col
                if self._backtrack(row + 1):
                    return True
                self.board[row] = -1
        return False

    def _is_valid(self, row, col):
        for i in range(row):
            if self.board[i] == col or abs(self.board[i] - col) == abs(i - row):
                return False
        return True

    def _create_output(self):
        output_board = []
        for row in range(self.size):
            line = ['.'] * self.size
            if self.board[row] != -1:
                line[self.board[row]] = 'Q'
            output_board.append(''.join(line))
        return output_board
```

